'use client';

import { useState, useEffect } from 'react';
import { trpc } from '../utils/trpc';

export default function Home() {
  const [messages, setMessages] = useState<string[]>([]);

  // tRPC v11 allows queries to return async iterables when using httpBatchStreamLink.
  // We can use useSuspenseQuery or useQuery. Wait, if it returns an async generator, 
  // how do we consume it in the client?
  // Actually, tRPC v11 client converts the async generator into an async iterable.
  // Or maybe we can just use `trpc.chatStream.query()` directly?
  // Let's use trpc.useUtils() and call query manually, or we can use the mutation/query.
  const utils = trpc.useUtils();

  useEffect(() => {
    let active = true;

    async function fetchStream() {
      try {
        const iterable = await utils.client.chatStream.query();
        // It returns an async iterable
        for await (const msg of iterable as any) {
          if (!active) break;
          setMessages((prev) => [...prev, msg]);
        }
      } catch (err) {
        console.error(err);
      }
    }

    fetchStream();

    return () => {
      active = false;
    };
  }, [utils]);

  return (
    <main className="p-8">
      <h1 className="text-2xl font-bold mb-4">AI Chat Stream</h1>
      <ul>
        {messages.map((msg, i) => (
          <li key={i}>{msg}</li>
        ))}
      </ul>
    </main>
  );
}

